solution:
apiVersion: v1
kind: ConfigMap
metadata:
  name: amazon-cloudwatch-agent
  namespace: amazon-cloudwatch
data:
  cwagentconfig.json: |
    {
      "agent": { "metrics_collection_interval": 60 },
      "metrics": {
        "metrics_collected": {
          "cpu": { "measurement": ["cpu_usage_idle"] },
          "disk": { "measurement": ["used_percent"], "resources": ["*"] },
          "mem": { "measurement": ["mem_used_percent"] }
        }
      }
    }
